-- pocket.migration.MsgClaimMorseSupplier → msg_claim_morse_supplier (additive)
ALTER TABLE msg_claim_morse_supplier ADD COLUMN IF NOT EXISTS morse_node_address TEXT NULL;
ALTER TABLE msg_claim_morse_supplier ADD COLUMN IF NOT EXISTS signer_is_output_address BOOLEAN NULL;
COMMENT ON COLUMN msg_claim_morse_supplier.morse_node_address IS 'The hex-encoded address of the Morse non-custodial (i.e. operator) account. - Unstaked balance will be migrated 1:1 - Stake will be migrated 1:1 from morse_node_address to shannon_operator_address - Morse non-custodial (i.e. operator) address. If morse_output_address is not set, this is the custodial address. - See ''pocket nodes --help'' for more information. Note that this refers to the Morse CLI. E.g.: 00f9900606fa3d5c9179fc0c8513078a53a2073e';
COMMENT ON COLUMN msg_claim_morse_supplier.signer_is_output_address IS 'Set to true if the private key corresponding to the morse_output_address is producing the morse_signature. For non-custodial claiming: - This MUST be true. - The morse_public_key MUST correspond to morse_output_address. - The morse_signature MUST correspond to morse_output_address.';
-- COMMENT refreshes (proto docstring changed since previous version)
COMMENT ON COLUMN msg_claim_morse_supplier.morse_public_key IS 'The ed25519 public key of EITHER the Morse node/supplier operator OR owner account. - MUST correspond to the private key which was used to produce the morse_signature. - MUST correspond to ONE OF THE FOLLOWING: - morse_node_address - morse_output_address';
COMMENT ON COLUMN msg_claim_morse_supplier.morse_signature IS 'The hex-encoded signature, of this message (where this field is nil). I.e.: morse_signature = private_key.sign(marshal(MsgClaimMorseSupplier{morse_signature: nil, ...})) - MUST match morse_public_key. - MUST be signed by ONE OF THE FOLLOWING: - Morse node account (i.e. operator); if signer_is_output_address is false - Morse output account (i.e. owner); if signer_is_output_address is true';

